"/*
    style.css - NYDC Crypto Paper Trading Platform
    Author: Antigravity AI
    Theme: Dark premium with glassmorphism and smooth animations
*/

/* ==== CSS Variables ==== */
:root {
  /* Colors */
  --bg-primary: #0B0F19;
  --panel-bg: #161B26;
  --card-bg: #1E293B;
  --accent: #2962FF;
  --profit: #00C853;
  --loss: #FF1744;
  --text-primary: #FFFFFF;
  --text-secondary: #9CA3AF;
  --glass-bg: rgba(22, 27, 38, 0.6);
  --glass-border: rgba(255, 255, 255, 0.1);

  /* Typography */
  --font-family: 'Inter', sans-serif;
  --fs-sm: 0.85rem;
  --fs-base: 1rem;
  --fs-lg: 1.2rem;
  --fs-xl: 1.5rem;

  /* Spacing */
  --spacing-xs: 0.25rem;
  --spacing-sm: 0.5rem;
  --spacing-md: 1rem;
  --spacing-lg: 1.5rem;
  --spacing-xl: 2rem;
}

/* ==== Global Reset ==== */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
  font-family: var(--font-family);
  background: var(--bg-primary);
  color: var(--text-primary);
  overflow: hidden;
  -webkit-font-smoothing: antialiased;
}

a {
  color: var(--accent);
  text-decoration: none;
}

button {
  cursor: pointer;
  border: none;
  background: none;
  font-family: inherit;
}

/* ==== Layout ==== */
.navbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: var(--spacing-sm) var(--spacing-md);
  background: var(--panel-bg);
  backdrop-filter: blur(8px);
  border-bottom: 1px solid var(--glass-border);
}

.nav-left {
  display: flex;
  align-items: center;
  gap: var(--spacing-sm);
}

.logo {
  width: 32px;
  height: 32px;
}

.competition-name {
  font-size: var(--fs-lg);
  font-weight: 600;
}

.search-bar {
  width: 250px;
  padding: var(--spacing-xs) var(--spacing-sm);
  border-radius: 8px;
  background: var(--glass-bg);
  border: 1px solid var(--glass-border);
  color: var(--text-primary);
  transition: border 0.2s ease;
}

